sp_widget.client_script:
api.controller = function() {
  var c = this;
  c.data = c.data || {};
};

sp_widget.css:
.sp-card-grid {
  display: flex;
  flex-wrap: wrap;
}
.sp-card-grid > [class*="col-"] {
  display: flex;
  margin-bottom: 24px;
}
.sp-stat-tile {
  background: $background-primary;
  border: 1px solid $border-tertiary;
  border-radius: $border-radius-large;
  padding: 24px;
  display: flex;
  align-items: center;
  gap: 16px;
  width: 100%;
  box-shadow: 0 1px 3px rgba($text-color, 0.06);
}
.sp-stat-icon {
  width: 48px;
  height: 48px;
  border-radius: $border-radius-large;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 20px;
  flex-shrink: 0;
}
.sp-stat-icon-info {
  background: $state-info-bg;
  color: $brand-info;
}
.sp-stat-icon-success {
  background: $state-success-bg;
  color: $brand-success;
}
.sp-stat-icon-warning {
  background: $state-warning-bg;
  color: $brand-warning;
}
.sp-stat-icon-danger {
  background: $state-danger-bg;
  color: $brand-danger;
}
.sp-stat-value {
  font-size: 32px;
  font-weight: 700;
  color: $text-color;
  line-height: 1;
}
.sp-stat-label {
  font-size: 12px;
  color: $text-muted;
  margin-top: 4px;
}

sp_widget.script:
(function() {
  data.stats = [];

  try {
    var tableName = 'x_2091449_manage_0_consumer_case';

    // Total Cases
    var totalGa = new GlideAggregate(tableName);
    totalGa.addAggregate('COUNT');
    totalGa.setLimit(1);
    totalGa.query();
    var totalCount = 0;
    if (totalGa.next()) {
      totalCount = parseInt(totalGa.getAggregate('COUNT')) || 0;
    }
    data.stats.push({ label: 'Total Cases', value: totalCount, icon: 'glyphicon-folder-open', type: 'info' });

    // Open Cases (state = 1 or 2)
    var openGa = new GlideAggregate(tableName);
    openGa.addAggregate('COUNT');
    openGa.addQuery('state', 'IN', '1,2');
    openGa.setLimit(1);
    openGa.query();
    var openCount = 0;
    if (openGa.next()) {
      openCount = parseInt(openGa.getAggregate('COUNT')) || 0;
    }
    data.stats.push({ label: 'Open Cases', value: openCount, icon: 'glyphicon-inbox', type: 'warning' });

    // Resolved Cases (state = 3)
    var resolvedGa = new GlideAggregate(tableName);
    resolvedGa.addAggregate('COUNT');
    resolvedGa.addQuery('state', '3');
    resolvedGa.setLimit(1);
    resolvedGa.query();
    var resolvedCount = 0;
    if (resolvedGa.next()) {
      resolvedCount = parseInt(resolvedGa.getAggregate('COUNT')) || 0;
    }
    data.stats.push({ label: 'Resolved Cases', value: resolvedCount, icon: 'glyphicon-ok-circle', type: 'success' });

    // Critical Cases (priority = 1)
    var critGa = new GlideAggregate(tableName);
    critGa.addAggregate('COUNT');
    critGa.addQuery('priority', '1');
    critGa.addQuery('active', true);
    critGa.setLimit(1);
    critGa.query();
    var critCount = 0;
    if (critGa.next()) {
      critCount = parseInt(critGa.getAggregate('COUNT')) || 0;
    }
    data.stats.push({ label: 'Critical Cases', value: critCount, icon: 'glyphicon-exclamation-sign', type: 'danger' });

  } catch (e) {
    gs.error('Case Stats widget error: ' + e.message);
  }
})();
